'use client'

import React from 'react'
import { Volume2, VolumeX } from 'lucide-react'
import { useAudio } from './audio-provider'

export function SoundToggle() {
  const { soundEnabled, toggleSound } = useAudio()

  return (
    <button
      onClick={toggleSound}
      className="fixed bottom-6 right-6 z-50 p-4 rounded-full border border-white/30 
                 bg-black/60 backdrop-blur-md 
                 text-white/80 hover:text-white hover:border-white/60 
                 hover:bg-black/80 transition-all duration-300 
                 shadow-lg hover:shadow-white/20"
      aria-label={soundEnabled ? 'Mute sounds' : 'Enable sounds'}
    >
      {soundEnabled ? (
        <Volume2 size={28} strokeWidth={1.5} />
      ) : (
        <VolumeX size={28} strokeWidth={1.5} />
      )}
    </button>
  )
}
